<?php
 namespace WPAICG\SEO\AIOSEO; if (!defined('ABSPATH')) { exit; } function update_meta_description_logic(int $post_id, string $description): bool { if (empty($post_id) || !is_string($description)) { return false; } $sanitized_description = sanitize_text_field($description); $meta_update_success = update_post_meta($post_id, '_aioseo_description', $sanitized_description) !== false; global $wpdb; $table_name = $wpdb->prefix . 'aioseo_posts'; $table_exists = ($wpdb->get_var($wpdb->prepare('SHOW TABLES LIKE %s', $table_name)) === $table_name); if (!$table_exists) { return $meta_update_success; } $existing_id = $wpdb->get_var($wpdb->prepare("SELECT id FROM {$table_name} WHERE post_id = %d", $post_id)); $timestamp = current_time('mysql', 1); if ($existing_id) { $result = $wpdb->update( $table_name, [ 'description' => $sanitized_description, 'updated' => $timestamp, ], ['post_id' => $post_id], ['%s', '%s'], ['%d'] ); } else { $result = $wpdb->insert( $table_name, [ 'post_id' => $post_id, 'description' => $sanitized_description, 'created' => $timestamp, 'updated' => $timestamp, ], ['%d', '%s', '%s', '%s'] ); } return $meta_update_success && $result !== false; } 